import{_ as t,o as a,c as o,a2 as r}from"./chunks/framework.c3r8iWL8.js";const m=JSON.parse('{"title":"SOP-004: Spec-Driven Implementation","description":"Reference template for AI-native enterprise delivery on AWS","frontmatter":{},"headers":[],"relativePath":"sops/SOP-004-implementation.md","filePath":"sops/SOP-004-implementation.md","lastUpdated":1782929962000}'),i={name:"sops/SOP-004-implementation.md"};function n(s,e,l,d,p,c){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="sop-004-spec-driven-implementation" tabindex="-1">SOP-004: Spec-Driven Implementation <a class="header-anchor" href="#sop-004-spec-driven-implementation" aria-label="Permalink to &quot;SOP-004: Spec-Driven Implementation&quot;">​</a></h1><p><strong>Version:</strong> 1.0 · <strong>Owner:</strong> Developer · <strong>Gate:</strong> G2</p><h2 id="purpose-scope" tabindex="-1">Purpose &amp; scope <a class="header-anchor" href="#purpose-scope" aria-label="Permalink to &quot;Purpose &amp; scope&quot;">​</a></h2><p>Implement features using AI-assisted coding bounded by Approved specs and Accepted ADRs.</p><h2 id="roles" tabindex="-1">Roles <a class="header-anchor" href="#roles" aria-label="Permalink to &quot;Roles&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Role</th><th>RACI</th></tr></thead><tbody><tr><td>DEV</td><td><strong>R/A</strong> — implementation</td></tr><tr><td>ARCH</td><td>C — design questions</td></tr><tr><td>AIPO</td><td>I — AI policy compliance</td></tr></tbody></table><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>Ticket has <code>implementation-unlocked</code> label</li><li>Approved spec path documented in ticket</li><li>Local dev environment per <a href="./SOP-011-onboarding.html">SOP-011</a></li><li><a href="./SOP-010-ai-tool-usage.html">SOP-010</a> acknowledged</li></ul><h2 id="procedure" tabindex="-1">Procedure <a class="header-anchor" href="#procedure" aria-label="Permalink to &quot;Procedure&quot;">​</a></h2><ol><li><strong>Load context</strong> — In Cursor: <code>@specs/openapi/...</code>, linked ADRs via MCP, ticket ID in branch name <code>feat/TICKET-123-...</code>.</li><li><strong>Scaffold</strong> — AI generates handler, DTO, mapper, contract test stubs from OpenAPI operation IDs.</li><li><strong>Implement</strong> — Steer AI operation-by-operation; do not implement undeclared endpoints.</li><li><strong>Tests</strong> — AI generates/updates: unit, contract (Schemathesis/Pact), integration if DB/queue involved.</li><li><strong>Local verification</strong> — <code>pre-commit run --all-files</code>; full local test suite green.</li><li><strong>Self-review</strong> — Diff against spec: every changed operation maps to OpenAPI path.</li><li><strong>Open PR</strong> — Template: spec link, ADR IDs, test evidence, tier label → <a href="./SOP-005-pr-review.html">SOP-005</a>.</li></ol><h2 id="definition-of-done-pr-ready" tabindex="-1">Definition of Done (PR ready) <a class="header-anchor" href="#definition-of-done-pr-ready" aria-label="Permalink to &quot;Definition of Done (PR ready)&quot;">​</a></h2><ul><li>[ ] All in-scope OpenAPI operations implemented</li><li>[ ] Contract tests cover 100% of touched operations</li><li>[ ] Unit tests for business logic branches</li><li>[ ] No secrets, no prod data in fixtures</li><li>[ ] PR template complete</li></ul><h2 id="anti-patterns-stop-and-escalate" tabindex="-1">Anti-patterns (stop and escalate) <a class="header-anchor" href="#anti-patterns-stop-and-escalate" aria-label="Permalink to &quot;Anti-patterns (stop and escalate)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Situation</th><th>Action</th></tr></thead><tbody><tr><td>Spec gap discovered</td><td>Stop coding → SOP-003 amendment PR</td></tr><tr><td>New architectural choice</td><td>Stop → SOP-002 ADR Proposed</td></tr><tr><td>AI suggests undeclared API</td><td>Reject; extend spec first</td></tr><tr><td>Tests fail intermittently</td><td>Fix before PR; no <code>@flaky</code> without SRE ticket</td></tr></tbody></table><h2 id="related-sops" tabindex="-1">Related SOPs <a class="header-anchor" href="#related-sops" aria-label="Permalink to &quot;Related SOPs&quot;">​</a></h2><ul><li><a href="./SOP-003-spec-approval.html">SOP-003</a> · <a href="./SOP-005-pr-review.html">SOP-005</a> · <a href="./SOP-010-ai-tool-usage.html">SOP-010</a></li></ul>',16)])])}const u=t(i,[["render",n]]);export{m as __pageData,u as default};
